import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String safeUserInput = sanitizeInput(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Hello " + safeUserInput + "!</h1>"); // Safe from XSS
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper input validation and encoding here
        // One way is to use OWASP Java Encoder library for encoding:
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

